    # this function gets triggered whenever the done button is clicked
    def Calculate(self):
        # read input from text box in the test UI
        # read cmd power input from the train controller
        powerCmd = self.poweripBoxTEST.toPlainText()
        # send cmd power input to the set_cmd_power function
        self.trainModel.set_cmd_power(float(powerCmd))
        # read cmd velocity input from the train controller
        velocityCmd = self.VcmdipBoxTEST.toPlainText()
        # send cmd velocity input to the set_cmd_velocity function
        self.trainModel.set_cmd_velocity(float(velocityCmd))
        # read passenger mass input from the track model
        PassengerMass = self.VcmdipBoxTEST_2.toPlainText()
        # send passenger mass input to the set_passenger_mass function
        self.trainModel.set_passenger_mass(float(PassengerMass))
        # post to the other text boxes:
        # read input from the text box in the test UI
        force = self.forceResultBoxTEST.toPlainText()
        mass = self.VcmdipBoxTEST_2.toPlainText()
        # refresh set commands:
        self.trainModel.set_passenger_mass(float(mass))
        # display on test ui
        self.forceipBoxTEST.setText(str(force))  # refresh text box with force
        # refresh mass text box with passenger mass
        self.massipBoxTEST.setText(str(mass))
        # read input from text box
        accel = self.accelResultBoxTEST.toPlainText()
        self.trainModel.set_accel(float(accel))
        # refresh set commands:
        # refresh accel text box with calculated acceleration
        self.accelipBoxTEST.setText(str(accel))

    def temp_control(self):
        # read input from the spin box
        temp = self.tempControlip_TEST.value()
        self.trainModel.set_temperature(float(temp))

    def update_line_info(self):
        # change output for each line
        if self.quickMetricsbaripTEST.currentText() == "Blue Line":
            # write metrics to the test UI
            self.AuthorityMetricsResultBoxTEST.setPlainText(
                f"Authority: mi")  # need to get this input from somewhere
            self.SpeedLimitMetricsResultBoxTEST.setPlainText(
                f"Speed Limit: mph")  # need to get this input from somewhere
