    # update function always gets called by handler function so that we continuously have updated values
    def update(self):
        _translate = QtCore.QCoreApplication.translate

        # print changed on train controller UI
        self.poweripBoxTEST.setPlainText(str(self.trainModel.get_cmd_power()))

        # update the test UI:
        self.BeaconResultBoxTEST.setText(str(self.trainModel.get_beacon()))
        self.TempResultBoxTEST.setPlainText(
            f"{str(self.trainModel.get_temperature())}°")
        self.TempMetricsResultBoxTEST.setPlainText(
            f"Temp:{str(self.trainModel.get_temperature())}°")
        self.forceResultBoxTEST.setText(str(self.trainModel.calc_Force()))
        self.accelResultBoxTEST.setText(
            str(self.trainModel.calc_acceleration()))
        # refresh actual velocity calculation in test UI
        self.VactualResultBoxTEST.setText(
            str(self.trainModel.calc_actual_velocity()))
        # update the main UI:
        try:
            self.ui.forceResultBoxMAIN.setText(
                str(round(self.trainModel.get_force(), 3)))
            self.ui.accelResultBoxMAIN.setText(
                str(round(self.trainModel.get_accel(), 3)))
            self.ui.VactualResultBoxMAIN.setText(
                str(round(self.trainModel.get_actual_velocity(), 3)))
            self.ui.BeaconResultBoxMAIN.setText(
                str(self.trainModel.get_beacon()))
            self.ui.TempMetricsResultBoxMAIN_2.setPlainText(
                f"Temp:{str(self.trainModel.get_temperature())}°")
            self.ui.serviceBrakeoutputMAIN.setPlainText(
                str(self.trainModel.get_service_brake()))
            self.ui.EbrakeoutputMAIN.setPlainText(
                str(self.trainModel.get_e_brake()))
            self.ui.LightoutputMAIN.setPlainText(
                str(self.trainModel.get_internal_lights()))
            self.ui.LightoutputMAIN_2.setPlainText(
                str(self.trainModel.get_external_lights()))
            self.ui.RdooroutputMAIN.setPlainText(
                str(self.trainModel.get_right_doors()))
            self.ui.LdooroutputMAIN.setPlainText(
                str(self.trainModel.get_left_doors()))
        except AttributeError:
            # print("cannot refresh attributes in main UI")
            print("")
        # check for failure modes
        self.check_power_failure()
        self.check_signal_failure()
        self.check_brake_failure()

    def _handler(self):
        self.timer = QTimer()
        self.timer.setInterval(100)  # refreshes every time period
        self.timer.timeout.connect(self.update)
        self.timer.start()

    # check for power failure:
    def check_power_failure(self):
        # if pCmd > Pmax
        if self.trainModel.get_cmd_power() > self.trainModel.Pmax:
            self.powerFailBoxTEST.setText(
                "Power/engine failure")  # display error message
            # refresh force result in the main UI:
            try:
                # refresh force calculation in test UI
                self.ui.powerFailBoxMAIN.setText("Power/engine failure")
            except AttributeError:
                print("")
        else:
            self.powerFailBoxTEST.setText(
                "power status: good")  # clear the error message
            try:
                # refresh force calculation in test UI
                self.ui.powerFailBoxMAIN.setText("power status: good")
            except AttributeError:
                print("")

    # check service brake failure:
    def check_signal_failure(self):
        if self.trainModel.get_signal_pickup_failure():
            self.SignalFailBoxTEST.setText(
                "Signal Pickup Failure")  # display error message
            # refresh force result in the main UI:
            try:
                self.ui.SignalFailBoxMAIN.setText(
                    "Signal Pickup Failure")  # refresh in main UI
            except AttributeError:
                print("")
        else:
            self.SignalFailBoxTEST.setText(
                "signal pick-up: good")  # clear error message
            # refresh force result in the main UI:
            try:
                self.ui.SignalFailBoxMAIN.setText(
                    "signal pick-up: good")  # refresh in main UI
            except AttributeError:
                print("")

    # check e-brake failure:
    def check_brake_failure(self):
        if self.trainModel.get_eBrake_failure():
            self.BrakeFailBoxTEST.setText("Emergency Brake Failure")
            try:
                self.ui.BrakeFailBoxMAIN.setText("Emergency Brake Failure")
            except AttributeError:
                print("")
        elif self.trainModel.get_service_brake_failure():
            self.BrakeFailBoxTEST.setText("Service Brake Failure")
            try:
                self.ui.BrakeFailBoxMAIN.setText("Service Brake Failure")
            except AttributeError:
                print("")
        else:
            self.BrakeFailBoxTEST.setText("Brake status: good")
            try:
                self.ui.BrakeFailBoxMAIN.setText("Brake status: good")
            except AttributeError:
                print("")

